-- Seed data: 30 orders spanning Jan–Dec 2025, varied amounts (some <20, some >300, some between)
-- Run via: make seed

BEGIN;

-- Wipe existing data to make seed idempotent.
-- Guard against running before migrations have created the tables.
DO $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM information_schema.tables
    WHERE table_schema = 'public' AND table_name = 'order_date'
  ) THEN
    TRUNCATE order_combined, order_detail, order_date CASCADE;
  END IF;
END $$;



COMMIT;
